// ============================================
// SCRIPT COMPLET - NODE CODE
// Input mergé: item HTTP ($resources) + items SQL (XSAL_0)
// Excel: toujours via $('Extract from File')
// ============================================

function excelDateToJSDate(excelDate) {
  if (!excelDate && excelDate !== 0) return null;

  // Cas 1: chaîne de type "JJ/MM/AAAA" ou "JJ-MM-AAAA" ou déjà "AAAA-MM-JJ"
  if (typeof excelDate === 'string') {
    const trimmed = excelDate.trim();

    // Déjà au format AAAA-MM-JJ ?
    if (/^\d{4}-\d{2}-\d{2}/.test(trimmed)) {
      return trimmed.substring(0, 10);
    }

    // Format JJ/MM/AAAA ou JJ-MM-AAAA
    const match = trimmed.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{4})/);
    if (match) {
      const [, day, month, year] = match;
      return `${year}-${month.padStart(2, '0')}-${day.padStart(2, '0')}`;
    }

    // Format non reconnu → essayer Date native en dernier recours
    const parsed = new Date(trimmed);
    if (!isNaN(parsed)) {
      const year = parsed.getFullYear();
      const month = String(parsed.getMonth() + 1).padStart(2, '0');
      const day = String(parsed.getDate()).padStart(2, '0');
      return `${year}-${month}-${day}`;
    }

    return null; // vraiment invalide
  }

  // Cas 2: numéro de série Excel
  if (isNaN(excelDate)) return null;

  const excelEpoch = new Date(1900, 0, 1);
  const jsDate = new Date(excelEpoch.getTime() + (excelDate - 2) * 86400000);

  const year = jsDate.getFullYear();
  const month = String(jsDate.getMonth() + 1).padStart(2, '0');
  const day = String(jsDate.getDate()).padStart(2, '0');

  return `${year}-${month}-${day}`;
}

// ============================================
// ÉTAPE 1 & 2: Séparer les items du merge
// - Item HTTP  → contient $resources  → types de primes
// - Items SQL  → contient XSAL_0      → codes X3
// ============================================
const allItems = $input.all();
const primeTypes = new Map();
const matToX3Map = new Map();

for (const item of allItems) {
  const data = item.json;

  // ── Item HTTP Request1 ──────────────────────
  if (data.$resources && Array.isArray(data.$resources)) {
    for (const resource of data.$resources) {
      primeTypes.set(resource.LANMES, resource.LANNUM);
    }
    console.log(`🏷️  Types de primes chargés: ${primeTypes.size}`);
  }

  // ── Items SQL ───────────────────────────────
  else if (data.XSAL_0 !== undefined) {
    if (data.STATUT !== 'NON_TROUVE' && data.XSAL_0 !== 'CODE_NON_TROUVE') {
      // Map par XMAT_0_ORIGINAL (la clé de recherche)
      matToX3Map.set(data.XMAT_0_ORIGINAL, {
        codeX3: data.XSAL_0,
        matUtilise: data.XMAT_0_UTILISE,
        statut: data.STATUT
      });
    }
  }
}

console.log(`✅ Codes X3 chargés: ${matToX3Map.size}`);

// Vérifications critiques
if (primeTypes.size === 0) {
  throw new Error('❌ Aucun type de prime trouvé ! Vérifier HTTP Request1');
}
if (matToX3Map.size === 0) {
  throw new Error('❌ Aucun code X3 trouvé ! Vérifier Microsoft SQL');
}

// ============================================
// ÉTAPE 3: Données Excel (source indépendante)
// ============================================
const excelData = $('Extract from File').all();

if (excelData.length === 0) {
  throw new Error('❌ Aucune donnée Excel trouvée !');
}

console.log(`📋 Lignes Excel: ${excelData.length}`);

const results = [];
const errors = [];

for (const item of excelData) {
  const row = item.json;
  const mat = String(row.MAT);
  const cleanName = String(row['Nom et prénom'] || '')
    .replace(/\r?\n|\r/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  // Vérifier le code X3
  const x3Info = matToX3Map.get(mat);
  if (!x3Info) {
    errors.push({
      type: 'CODE_X3_MANQUANT',
      MAT: mat,
      Nom: cleanName,
      message: 'Code X3 non trouvé dans la base'
    });
    continue;
  }

  // Vérifier le type de prime
  const typePrime = row['Type de Prime'];
  const codeTypePrime = primeTypes.get(typePrime);
  if (codeTypePrime === undefined) {
    errors.push({
      type: 'TYPE_PRIME_INVALIDE',
      MAT: mat,
      Nom: cleanName,
      TypePrime: typePrime,
      message: `Type de prime "${typePrime}" non trouvé dans X3`
    });
    continue;
  }

  // Convertir les dates (même format pour les deux: YYYY-MM-DD)
  const datePaiement = excelDateToJSDate(row['Date paiement']);
  const moisPrime    = excelDateToJSDate(row['Mois de Prime']);
  if (!datePaiement || !moisPrime) {
    errors.push({
      type: 'DATE_INVALIDE',
      MAT: mat,
      Nom: cleanName,
      DatePaiement: row['Date paiement'],
      MoisPrime: row['Mois de Prime'],
      message: 'Date(s) invalide(s)'
    });
    continue;
  }

  // Valider le montant
  const montant = parseFloat(row['Montant Prime']);
  if (isNaN(montant) || montant < 0) {
    errors.push({
      type: 'MONTANT_INVALIDE',
      MAT: mat,
      Nom: cleanName,
      Montant: row['Montant Prime'],
      message: 'Montant invalide'
    });
    continue;
  }

  // ✅ Tout valide
  results.push({
    json: {
      YREP:    x3Info.codeX3,
      YNAM:    cleanName,
      YDATC:   moisPrime,
      YDATPAY: datePaiement,
      YMONTP:  montant,
      YOBS:    row['OBSERVATION '] || '',
      YTYPP:   codeTypePrime,
      _debug: {
        MAT_ORIGINAL:       mat,
        XMAT_UTILISE:       x3Info.matUtilise,
        STATUT_RECHERCHE:   x3Info.statut,
        TYPE_PRIME_LABEL:   typePrime,
        DATE_PAIEMENT_ORIGINAL: row['Date paiement'],
        MOIS_PRIME_ORIGINAL:    row['Mois de Prime']
      }
    }
  });
}

// ============================================
// RAPPORT FINAL
// ============================================
console.log('\n=== RAPPORT DE TRAITEMENT ===');
console.log(`📊 Total lignes Excel  : ${excelData.length}`);
console.log(`✅ Lignes valides      : ${results.length}`);
console.log(`❌ Lignes avec erreurs : ${errors.length}`);

if (errors.length > 0) {
  const errorsByType = {};
  errors.forEach(err => {
    if (!errorsByType[err.type]) errorsByType[err.type] = [];
    errorsByType[err.type].push(err);
  });

  Object.keys(errorsByType).forEach(type => {
    console.log(`\n🔴 ${type} (${errorsByType[type].length}):`);
    errorsByType[type].forEach(err => {
      console.log(`   - MAT: ${err.MAT} | ${err.Nom} → ${err.message}`);
      if (err.TypePrime) console.log(`     Type prime: "${err.TypePrime}"`);
    });
  });

  if (errorsByType.TYPE_PRIME_INVALIDE) {
    console.log('\n💡 Types valides:', Array.from(primeTypes.keys()).join(', '));
  }
}

if (results.length > 0) {
  const statutStats = {};
  results.forEach(r => {
    const s = r.json._debug.STATUT_RECHERCHE;
    statutStats[s] = (statutStats[s] || 0) + 1;
  });
  console.log('\n=== STATISTIQUES CODES X3 ===');
  Object.keys(statutStats).forEach(s => console.log(`   ${s}: ${statutStats[s]}`));

  const primeStats = {};
  results.forEach(r => {
    const t = r.json._debug.TYPE_PRIME_LABEL;
    primeStats[t] = (primeStats[t] || 0) + 1;
  });
  console.log('\n=== STATISTIQUES TYPES DE PRIMES ===');
  Object.keys(primeStats).forEach(t => console.log(`   ${t}: ${primeStats[t]}`));
}

console.log('\n✨ Traitement terminé');
return results;

const annee = new Date().getFullYear().toString();

return $input.all().map(item => {
  const ydatcRaw = (item.json.YDATC || '').toString().trim();

  let ydatc = null;

  if (ydatcRaw) {
    // Cas 1 : déjà une date ISO "YYYY-MM-DD" → on garde telle quelle
    if (/^\d{4}-\d{2}-\d{2}$/.test(ydatcRaw)) {
      ydatc = ydatcRaw;
    }
    // Cas 2 : nom de mois en texte (ex: "mai", "janvier") → on convertit
    else {
      const moisMapping = {
        'janvier': '01', 'février': '02', 'fevrier': '02',
        'mars': '03', 'avril': '04', 'mai': '05', 'juin': '06',
        'juillet': '07', 'août': '08', 'aout': '08',
        'septembre': '09', 'octobre': '10', 'novembre': '11',
        'décembre': '12', 'decembre': '12',
      };
      const moisNum = moisMapping[ydatcRaw.toLowerCase()];
      ydatc = moisNum ? `${annee}-${moisNum}-01` : null;
    }
  }

  // Nettoyer YOBS : supprimer \n et caractères spéciaux problématiques
  const yobs = (item.json.YOBS || '')
    .replace(/\n/g, ' ')
    .replace(/\r/g, ' ')
    .trim();

  return {
    json: {
      ...item.json,
      YDATC: ydatc,
      YOBS: yobs,
    }
  };
});
